INSERT INTO evidence_sources (ref_id,source_type,first_author_last,first_author_first,author_count,author_count_is_complete,is_corporate_primary,pub_year,pub_title,journal_name,doi,url,jurisdiction,language,lang_detected,tier,evidence_type,scope,verification_status,metadata_quality,doi_resolution_outcome,url_resolution_outcome,verified_by_tool,last_verified_at,prior_expectation,search_queries_used,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('REF-00930','journal_article','Koontz','Alicia',4,1,0,2018,'Effects of grab bars and backrests on independent wheelchair transfer performance and technique','Physiotherapy Research International','10.1002/pri.1758','https://doi.org/10.1002/pri.1758','US','en','en',3,'clinical','lower_control','VERIFIED','COMPLETE','RESOLVED','RESOLVED','scholar_gateway','2026-07-24T07:08:00+00:00','Searched for wheelchair manoeuvring/turning anthropometry; expected turning-footprint data. This source instead evidences grab-bar and backrest effects on transfer — a spillover to the grab-bar slug, not manoeuvring.','Scholar Gateway: wheelchair manoeuvring space turning circle anthropometric requirements built environment (spillover hit)','SPILLOVER: surfaced under a manoeuvring-footprint search but evidences grab-bar/backrest effects on independent wheelchair transfer. Tier 3 clinical. Filed to fold-down-grab-bar-specification, NOT manoeuvring. (Koontz group; cf. GAP-019 Koontz 2012.)','2026-07-24T07:08:00+00:00','session_2026-07-24-research-matrix-completion','2026-07-24T07:08:00+00:00','session_2026-07-24-research-matrix-completion');
